// wrangler.toml: binding name = "AI", model = "@cf/meta/llama-3.1-8b-instruct"

export interface Env {
  AI: Ai;
  AGENT_KV: KVNamespace;  // Cloudflare KV for conversation history
}

export default {
  async fetch(request: Request, env: Env): Promise<Response> {
    const { sessionId, message } = await request.json<{
      sessionId: string;
      message: string;
    }>();

    // Load conversation history from KV (edge-replicated store)
    const rawHistory = await env.AGENT_KV.get(`history:${sessionId}`);
    const history: Array<{ role: string; content: string }> =
      rawHistory ? JSON.parse(rawHistory) : [];

    history.push({ role: "user", content: message });

    // Run inference directly at the PoP -- no origin round-trip
    const stream = await env.AI.run("@cf/meta/llama-3.1-8b-instruct", {
      messages: [
        { role: "system", content: "You are a concise assistant." },
        ...history,
      ],
      stream: true,
      max_tokens: 512,
    });

    // Persist updated history asynchronously -- do not block the response
    const assistantReply = "";  // collect via stream in production
    request.ctx?.waitUntil(
      env.AGENT_KV.put(
        `history:${sessionId}`,
        JSON.stringify([...history, { role: "assistant", content: assistantReply }]),
        { expirationTtl: 3600 }  // 1-hour session TTL
      )
    );

    return new Response(stream, {
      headers: { "Content-Type": "text/event-stream" },
    });
  },
};

// Cloudflare Worker: classify search query and expand at the edge

export default {
  async fetch(request: Request, env: Env): Promise<Response> {
    const { query, userId } = await request.json<{ query: string; userId: string }>();

    // Step 1: classify intent at edge (fast, cheap)
    const intentResult = await env.AI.run("@cf/microsoft/phi-2", {
      prompt: `Classify this product search query into ONE of: [electronics, apparel, home, grocery, other].\nQuery: "${query}"\nCategory:`,
      max_tokens: 10,
    });

    const category = intentResult.response.trim().toLowerCase();

    // Step 2: for well-known categories, expand query at edge
    if (["electronics", "apparel", "home", "grocery"].includes(category)) {
      const expansionResult = await env.AI.run("@cf/microsoft/phi-2", {
        prompt: `Expand this ${category} search query with 3 related keywords (comma-separated):\nQuery: "${query}"\nKeywords:`,
        max_tokens: 50,
      });

      return Response.json({
        category,
        expandedKeywords: expansionResult.response.trim().split(",").map((k: string) => k.trim()),
        handledAt: "edge",
      });
    }

    // Step 3: unknown category -- forward to origin cloud for full processing
    const originResponse = await fetch("https://api.example.com/search/classify", {
      method: "POST",
      body: JSON.stringify({ query, userId }),
      headers: { "Content-Type": "application/json" },
    });
    const originData = await originResponse.json();
    return Response.json({ ...originData, handledAt: "cloud" });
  },
} satisfies ExportedHandler<Env>;
